import React from "react";
import Header from "./components/Header";
import Footer from "./components/Footer";
import items from "./components/Footer";

class App extends React.Component{
  constructor(props) {
    super(props);
    this.state = {
      items: [
      {
        id: 1,
        title: "Modern Armchair",
        description: "Comfortable armchair with wooden legs and soft fabric upholstery.",
        img: "armchair.jpg",
        category: "chairs",
        price: "$120"
      },
      {
        id: 2,
        title: "Oak Dining Table",
        description: "Solid oak dining table, seats up to 6 people.",
        img: "dining_table.jpg",
        category: "tables",
        price: "$350"
      },
      {
        id: 3,
        title: "Queen Size Bed",
        description: "Spacious queen size bed with upholstered headboard.",
        img: "bed.jpg",
        category: "beds",
        price: "$499"
      },
      {
        id: 4,
        title: "Classic Bookshelf",
        description: "Tall bookshelf with five adjustable shelves.",
        img: "bookshelf.jpg",
        category: "storage",
        price: "$180"
      },
      {
        id: 5,
        title: "Leather Sofa",
        description: "Three-seater leather sofa with plush cushions.",
        img: "sofa.jpg",
        category: "sofas",
        price: "$650"
      },
      {
        id: 6,
        title: "Nightstand",
        description: "Compact nightstand with drawer and open shelf.",
        img: "nightstand.jpg",
        category: "bedroom",
        price: "$75"
      }
      ],
    };
  }
  render() {
    return (
      <div className="wrapper">
        <Header />

        <Footer />
      </div>
    );
  }
}

export default App;
